import { MessageEvent } from '@nitrots/nitro-renderer';
import { TokenPurchaseOkParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/TokenPurchaseOkParser';

export class TokenPurchaseOkEvent extends MessageEvent {
    constructor(callBack: (event: TokenPurchaseOkEvent) => void) {
        super(callBack, TokenPurchaseOkParser);
    }

    public getParser(): TokenPurchaseOkParser {
        return this.parser as TokenPurchaseOkParser;
    }
}

// Bridge to your React view (DiamondsStoreView listens to "store_tokens_purchase_ok_raw")
export const tokenPurchaseOkEventCallback = (event: TokenPurchaseOkEvent) => {
    const p = event.getParser();
    window.dispatchEvent(
        new CustomEvent('store_tokens_purchase_ok_raw', {
            detail: {
                tokenId: p.tokenId,
                diamonds: p.diamonds,
                activeUntilTs: p.activeUntilTs,
            },
        })
    );
};
